import React, { useRef } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { Float, MeshPresence } from '@react-three/drei';

function Rings() {
  const ring1 = useRef();
  const ring2 = useRef();

  useFrame((state) => {
    const t = state.clock.getElapsedTime();
    ring1.current.rotation.x = t * 0.5;
    ring1.current.rotation.y = t * 0.2;
    ring2.current.rotation.x = t * 0.3;
    ring2.current.rotation.z = t * 0.5;
  });

  return (
    <group scale={1.5}>
      <mesh ref={ring1}>
        <torusGeometry args={[1, 0.05, 16, 100]} />
        <meshStandardMaterial color="#D4AF37" metalness={1} roughness={0.1} />
      </mesh>
      <mesh ref={ring2} rotation={[Math.PI / 2, 0, 0]}>
        <torusGeometry args={[1.1, 0.05, 16, 100]} />
        <meshStandardMaterial color="#C5A059" metalness={1} roughness={0.1} />
      </mesh>
    </group>
  );
}

export default function ThreeRings() {
  return (
    <div className="h-full w-full absolute inset-0 opacity-60">
      <Canvas camera={{ position: [0, 0, 5] }}>
        <ambientLight intensity={0.8} />
        <pointLight position={[10, 10, 10]} intensity={1} />
        <spotLight position={[-10, 10, 10]} angle={0.15} penumbra={1} />
        <Rings />
      </Canvas>
    </div>
  );
}
